import React from 'react'
import Axios from "axios"
import { useState, useEffect } from 'react'
import './Sessions.css'
import Calendar from 'react-calendar';

export const Sessions = () => {


    // useState to make API data extraction synchronous
    // const [sessions, setSession] = useState([])

    // useEffect(() => {
    //     // call the API by Axios to display formations in the collection formations in the PFA DB here
    //     Axios.get("http://localhost:5000/sessions")
    //     .then(res => {
    //       setSession(res.data)
    //     })
    //   }, [])

            const [selectedDate, setSelectedDate] = useState(null);
            const [sessions, setSession] = useState(null);
        
            const handleDateClick = async (date) => {
             setSelectedDate(date);
             console.log(date);
             const formattedDate = date.toISOString();
             console.log(formattedDate);
            try {
                const response = await Axios.get(`http://localhost:5000/sessions/${formattedDate}`);
                setSession(response.data);
            } catch (error) {
                console.error(error);
            }
            };


  return (
    <div className='sessions-container'>
        {/* <h2>The Events that will happened at the date : "03/05/2023"</h2>
        <table  className='T8'>
            <thead>
                <tr>
                    <th>Event</th>
                    <th>Classroom</th>
                    <th>Session</th>
                    <th>StartHour</th>
                    <th>EndHour</th>
                    <th>Trainer</th>
                </tr>
            </thead>
            <tbody>
                {sessions.map(session => {
                    return(
                        <tr key={session._id}>
                            <td>{session.EventName}</td>
                            <td>{session.EventRoom}</td>
                            <td>{session.EventSession}</td>
                            <td>{session.EventStartHour}</td>
                            <td>{session.EventEndHour}</td>
                            <td>{session.formateurFirstName} {session.formateurLastName}</td>
                        </tr>
                    )
                })}
            </tbody>
        </table> */}


        <h2 style={{color:"gray", fontFamily:"cursive"}}>Calendar Date Picker</h2>
        <Calendar onClickDay={(date) => handleDateClick(date)} value={selectedDate} />
{sessions.length > 0 ? (
  sessions.map((session) => (
    <div className="session-details" key={session._id}>
      <h3>Event Name: {session.EventName}</h3>
      <h3>Event Nature: {session.EventNature}</h3>
      <h3>Event Room: {session.room}</h3>
      <h3>Event Session Number : {session.EventSession}</h3>
      <h3>Event Start Hour: {session.EventStartHour}</h3>
      <h3>Event End Hour: {session.EventEndHour}</h3>
      <h3>Event Trainer: {session.formateurFirstName} {session.formateurLastName}</h3>
    </div>
  ))
) : (
  <p>No sessions found for the selected date.</p>
)}


    </div>
  )
}
